import time
import functools
from typing import Callable, Type, Tuple, Any, TypeVar, cast

F = TypeVar('F', bound=Callable[..., Any])

def retry(
    max_attempts: int = 3,
    backoff_factor: float = 2,
    exceptions: Tuple[Type[BaseException], ...] = (Exception,)
) -> Callable[[F], F]:
    """
    Decorator that retries a function on specified exceptions with exponential backoff.

    Args:
        max_attempts (int): Maximum number of attempts before giving up. Must be >= 1.
        backoff_factor (float): Multiplier for the delay between retries. Delay doubles each retry.
        exceptions (Tuple[Type[BaseException], ...]): Exception types to catch and retry on.

    Returns:
        Callable[[F], F]: Decorated function with retry logic.

    Raises:
        The last exception raised by the decorated function after exhausting retries.
    """
    if max_attempts < 1:
        raise ValueError("max_attempts must be at least 1")
    if backoff_factor <= 0:
        raise ValueError("backoff_factor must be positive")

    def decorator(func: F) -> F:
        @functools.wraps(func)
        def wrapper(*args: Any, **kwargs: Any) -> Any:
            attempt = 0
            delay = 1.0  # initial delay in seconds
            while attempt < max_attempts:
                try:
                    return func(*args, **kwargs)
                except exceptions as e:
                    attempt += 1
                    if attempt == max_attempts:
                        raise
                    time.sleep(delay)
                    delay *= backoff_factor
        return cast(F, wrapper)
    return decorator
```

